Part 7: Handling Response Metadata and Status Codes
Let’s explore what happens when things go wrong:

# Try requesting a resource that doesn't exist
bad_url &lt;- "https://jsonplaceholder.typicode.com/users/999999"

req &lt;- request(bad_url)
response &lt;- req_perform(req)

# Check the status
cat("Status code:", resp_status(response), "\n")


# Build a robust request handler
safe_get &lt;- function(url) {
  req &lt;- request(url)
  response &lt;- req_perform(req)
  status &lt;- resp_status(response)

  if (status == 200) {
    cat("Success! Status:", status, "\n")
    return(resp_body_json(response))
  } else if (status &gt;= 400 & status &lt; 500) {
    cat("Client error! Status:", status, "- Check your URL or parameters.\n")
    return(NULL)
  } else if (status &gt;= 500) {
    cat("Server error! Status:", status, "- The server has an issue.\n")
    return(NULL)
  }
}

# Test it
result &lt;- safe_get("https://jsonplaceholder.typicode.com/users/1")

Exercise 3: Retrieve Genres and Join
TMDB’s results include genre_ids (numbers) rather than genre names. This exercise fetches the genre lookup table and joins it.

req &lt;- request("https://api.themoviedb.org/3/genre/movie/list") |&gt;
  req_headers(Authorization = glue("Bearer {tmdb_token}")) |&gt;
  req_url_query(language = "en-US")

genre_data &lt;- resp_body_json(req_perform(req))

genre_df &lt;- lapply(genre_data$genres, function(g) {
  data.frame(genre_id = g$id, genre_name = g$name)
}) |&gt; bind_rows()

print(genre_df)


# For each movie, get its primary genre (first in the list)
popular_df_genres &lt;- popular_df |&gt;
  mutate(primary_genre_id = as.integer(sub(",.*", "", genre_ids))) |&gt;
  left_join(genre_df, by = c("primary_genre_id" = "genre_id"))

popular_df_genres |&gt;
  count(genre_name, sort = TRUE)


popular_df_genres |&gt;
  count(genre_name, sort = TRUE) |&gt;
  filter(!is.na(genre_name)) |&gt;
  ggplot(aes(x = reorder(genre_name, n), y = n, fill = n)) +
  geom_col(width = 0.7) +
  scale_fill_gradient(low = "#a5b4fc", high = "#4f46e5") +
  coord_flip() +
  labs(
    title = "Most Common Genres Among Currently Popular Movies",
    x     = NULL,
    y     = "Number of Movies",
    fill  = "Count"
  ) +
  theme_minimal(base_size = 13) +
  theme(legend.position = "none")

Exercise 4: Paginate Through Results
TMDB returns 20 results per page. This exercise collects multiple pages.

get_popular_page &lt;- function(page, token) {
  req &lt;- request("https://api.themoviedb.org/3/movie/popular") |&gt;
    req_headers(Authorization = glue("Bearer {token}")) |&gt;
    req_url_query(language = "en-US", page = page)

  data &lt;- resp_body_json(req_perform(req))

  lapply(data$results, function(m) {
    data.frame(
      title        = m$title,
      vote_average = m$vote_average,
      popularity   = m$popularity
    )
  }) |&gt; bind_rows()
}

# Collect 3 pages (60 movies)
pages_1_to_3 &lt;- lapply(1:3, get_popular_page, token = tmdb_token) |&gt;
  bind_rows()

cat("Total movies collected:", nrow(pages_1_to_3), "\n")

